--- test/auth.test.js ---
import { test } from "node:test";
import assert from "node:assert/strict";
import { createApp } from "../src/app.js";
import { issueToken, verifyToken, inspect } from "../src/auth.js";
import { listen } from "./helpers.js";

test("issues a token whose payload round-trips through verify", () => {
  const token = issueToken({ sub: "alice", role: "member" }, 3600);
  const claims = verifyToken(token);
  assert.equal(claims.sub, "alice");
  assert.equal(claims.role, "member");
  assert.equal(typeof claims.exp, "number");
  assert.equal(claims.exp - claims.iat, 3600);
});

test("signs with HS256 and exposes the header via decode(complete)", () => {
  const decoded = inspect(issueToken({ sub: "bob" }));
  assert.equal(decoded.header.alg, "HS256");
  assert.equal(decoded.header.typ, "JWT");
});

test("login then /me returns the authenticated user", async () => {
  const { base, close } = await listen(createApp());
  try {
    const login = await fetch(`${base}/login`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ user: "carol" }),
    });
    assert.equal(login.status, 200);
    const { token } = await login.json();
    const me = await fetch(`${base}/me`, {
      headers: { authorization: `Bearer ${token}` },
    });
    assert.equal(me.status, 200);
    assert.equal((await me.json()).user, "carol");
  } finally {
    close();
  }
});

test("rejects a garbage token", async () => {
  const { base, close } = await listen(createApp());
  try {
    const me = await fetch(`${base}/me`, {
      headers: { authorization: "Bearer not.a.jwt" },
    });
    assert.equal(me.status, 401);
  } finally {
    close();
  }
});
--- test/fetch.test.js ---
import { test, before, after } from "node:test";
import assert from "node:assert/strict";
import http from "node:http";
import { parseFetchOptions, preview } from "../src/fetch.js";

// A tiny local origin so the axios path is exercised without real network.
let server;
let base;

before(async () => {
  server = http.createServer((req, res) => {
    if (req.url === "/hello") {
      res.setHeader("content-type", "text/plain");
      res.end("hello world");
    } else if (req.url === "/once") {
      res.writeHead(302, { location: "/hello" });
      res.end();
    } else {
      res.writeHead(404);
      res.end("nope");
    }
  });
  await new Promise((r) => server.listen(0, r));
  base = `http://127.0.0.1:${server.address().port}`;
});

after(() => server.close());

test("parses flat query params", () => {
  assert.deepEqual(parseFetchOptions("timeout=1234&maxRedirects=2"), {
    timeout: 1234,
    maxRedirects: 2,
  });
});

test("defaults when params are absent", () => {
  assert.deepEqual(parseFetchOptions(""), { timeout: 5000, maxRedirects: 5 });
});

test("preview returns a plain 200 response", async () => {
  const out = await preview(`${base}/hello`);
  assert.equal(out.status, 200);
  assert.match(out.snippet, /hello world/);
});

test("preview follows a redirect to the final body", async () => {
  const out = await preview(`${base}/once`, "maxRedirects=3");
  assert.equal(out.status, 200);
  assert.match(out.snippet, /hello world/);
});
--- test/helpers.js ---
// Start an app (or any express instance) on an ephemeral port and return a
// base URL + a close fn. Keeps tests dependency-free (no supertest).
export async function listen(app) {
  const server = await new Promise((resolve) => {
    const s = app.listen(0, () => resolve(s));
  });
  const { port } = server.address();
  return { base: `http://127.0.0.1:${port}`, close: () => server.close() };
}
--- test/importer.test.js ---
import { test, before, after } from "node:test";
import assert from "node:assert/strict";
import http from "node:http";
import { fetchXml, importBookmarks } from "../src/importer.js";
import { createApp } from "../src/app.js";
import { listen } from "./helpers.js";

const SAMPLE = `<?xml version="1.0"?>
<bookmarks>
  <bookmark><title>Docs</title><url>https://docs.example.com</url></bookmark>
  <bookmark><title>Status</title><url>https://status.example.com</url></bookmark>
</bookmarks>`;

let origin;
let originBase;

before(async () => {
  origin = http.createServer((req, res) => {
    if (req.url === "/feed.xml") {
      res.setHeader("content-type", "application/xml");
      res.end(SAMPLE);
    } else {
      res.writeHead(404);
      res.end();
    }
  });
  await new Promise((r) => origin.listen(0, r));
  originBase = `http://127.0.0.1:${origin.address().port}`;
});

after(() => origin.close());

test("fetches a remote XML feed via request", async () => {
  const body = await fetchXml(`${originBase}/feed.xml`);
  assert.match(body, /<bookmarks>/);
});

test("parses bookmarks out of the XML", async () => {
  const items = await importBookmarks(SAMPLE);
  assert.equal(items.length, 2);
  assert.deepEqual(items[0], { title: "Docs", url: "https://docs.example.com" });
});

test("POST /import ingests an XML body", async () => {
  const { base, close } = await listen(createApp());
  try {
    const res = await fetch(`${base}/import`, {
      method: "POST",
      headers: { "content-type": "application/xml" },
      body: SAMPLE,
    });
    assert.equal(res.status, 200);
    assert.equal((await res.json()).imported, 2);
  } finally {
    close();
  }
});

